#include <bits/stdc++.h>
using namespace std;
int a,b,c,x,y,z;
bool flag=true;
bool use[10];
void dfs(int p){
    if(p>9){
        if(x%a==0 && y%b==0 && z%c==0 && x/a==y/b && y/b==z/c){
            printf("%d %d %d\n",x,y,z);
            flag=0;
        }
        return;
    }
    for(int i=1;i<=9;i++)
        if(!use[i]){
            use[i]=1;
            if(p<4)
                x=x*10+i;
            else if(p<7)
                y=y*10+i;
            else
                z=z*10+i;
            dfs(p+1);
            use[i]=0;
            if(p<4)
                x/=10;
            else if(p<7)
                y/=10;
            else
                z/=10;
        }
}
int main(){
    scanf("%d%d%d",&a,&b,&c);
    if(!a || !b || !c){
        printf("No!!!");
        return 0;
    }
    dfs(1);
    if(flag)
        printf("No!!!");
    return 0;
}
